var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>캄파멘토</color>\\n베이스 캠프, 최종 방어 라인 <color=#ffd34c>CSE</color> LV. 3","JPN":"管理局直轄都市<color=#ffd34c>カンパメント</color>\\nベースキャンプ、最終防衛線<color=#ffd34c>CSE</color> LV.3","ENG":"[[","TWN":"管理局直轄市 <color=#ffd34c>坎帕門托</color>\\n營區最後防線<color=#ffd34c>CSE</color> LV. 3","SCN":"管理局直属城市<color=#ffd34c>坎帕门托</color>\\n基地营地，最终防线<color=#ffd34c>CSE</color> LV. 3","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"베이스 캠프 안쪽까지 침식 지대가 퍼졌다고?","JPN":"ベースキャンプの内側まで侵食地帯が広まった？","ENG":"The Corrupted Area spread all the way inside the base camp?","TWN":"侵蝕地帶擴散到營區內部了嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"캄파멘토의 침식파 억제기가 기능을 못할 지경이라 카면, 이거 보통 큰 일이 아이네!","JPN":"カンパメントの侵食波抑制装置が機能せえへんなんて……大変やないか！","ENG":"If Campamento's Corruption Inhibitor can't even function, this is no ordinary crisis!","TWN":"如果坎帕門托的侵蝕波抑制器失效的話，那可真是大事不妙！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 로빈! 뭐하노! 멀뚱히 서 있지 말고 어서 뛰라!","JPN":"ロビン、何しとる！　ぼーっとせんで早う走れ！","ENG":"Come on, Robin! Don't just stand there! Move it!","TWN":"喂，蘿蘋！你在幹嘛呢！別傻站著，快跑！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"미, 미리네 씨!","JPN":"マ、マリさん！","ENG":"M-Ms. Mi Rinae!","TWN":"宓，宓璃奈！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"침식체들이 저렇게 몰려오잖아요! 저분들을 이대로 내버려 둘 수는 없어요!","JPN":"侵食体が押し寄せてきています！　皆さんをこのまま放って置くわけにはいきません！","ENG":"C.O.s are swarming in! We can't just leave them!","TWN":"侵蝕體湧過來了！我們不能坐視不管！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"쌤이 한 말을 잊었나? 우리한테는 해야 할 일이 있다 아이가!","JPN":"先生に言われたこと忘れたんか？　ウチらにはやらなあかんことがある！","ENG":"Did you forget what Teach said? We have our own mission here!","TWN":"你忘了老師說的話嗎？我們還有重要的事情要做！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"저 사람들, 우리를 위해 시간을 벌어주고 있는 거 안 보이나?","JPN":"あの人たち、ウチらのために時間稼いでくれてんねん！","ENG":"Can't you see they're buying us time?","TWN":"你難道看不出大家在為我們爭取時間嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그, 그렇지만…….","JPN":"で、でも……","ENG":"Y-yes, but...","TWN":"可，可是……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그라운드원에서 오신 카운터 분들이시죠?","JPN":"お二人はグラウンド・ワンからいらしたカウンターですよね？","ENG":"You're the Counters sent from Ground One, right?","TWN":"你們是來自G1的制裁者吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"말씀은 이미 들었습니다! 이 구역은 저희에게 맡겨 주십시오!","JPN":"話は聞いております！　この区域は我々にお任せください！","ENG":"We've been briefed! Leave this sector to us!","TWN":"我們已經聽說了！這個區域就交給我們吧！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"캄파멘토 관리국은 강합니다! 담당 태스크 포스들과의 결속력도 강하고요!","JPN":"カンパメント管理局は強い！　担当タスクフォースとの結束力も強いんです！","ENG":"Campamento Administration is strong! Our TASKFORCEs are tightly bonded!","TWN":"坎帕門托管理局很強大！負責的特遣勢力之間凝聚力也很強！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"맞습니다! 이 정도 재난은 베이스 캠프에서 한 발자국만 나가도 흔해요!","JPN":"そうです！　この程度の災難、ベースキャンプから一歩外に出ればよくあることです！","ENG":"That's right! Disasters like this are practically routine just outside base camp!","TWN":"沒錯！這種程度的災難在營區很常見！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그러니 저희를 믿고 가십시오! 가서, 저희 VIP를 구해주십시오!","JPN":"だから私たちを信じて、行ってください！　そしてVIPを助けてください！","ENG":"So trust us and go! Save our VIP!","TWN":"所以請相信我們！快走吧，救出我們的VIP！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"괴짜긴 하지만, 그래도 없어서는 안 되는 분입니다!","JPN":"変わり者ですが、それでもなくてはならない方なんです！","ENG":"He may be eccentric, but we can't do without him!","TWN":"雖然他是個怪人，但卻是個不可或缺的人物！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하핫! 다들 걱정 붙들어매이소!","JPN":"ははっ！　任しとき！","ENG":"Haha! Don't you worry!","TWN":"哈哈！大家別擔心！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"저희는 그라운드 관리국 정예 중 정예니까요. 칸 영감님은 반드시 구해오겠습니다.","JPN":"ウチらはグラウンドの管理局でも精鋭の中の精鋭やかんな。カンのじじいは必ず助け出すで。","ENG":"We're Ground Administration's finest of the fine. We'll bring back old man Khan safe and sound.","TWN":"我們可是管理局精英中的精英，一定會把坎老頭救回來的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"맞제, 로빈아?","JPN":"な？　ロビン。","ENG":"Right, Robin?","TWN":"對吧，蘿蘋？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"네? 아아, 네……!","JPN":"え？　ああ、はい……！","ENG":"Huh? Ah, yes...!","TWN":"嗯？嗯嗯，沒錯……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"기사의 명예를 걸고, 여러분께 약속할게요!","JPN":"騎士の名誉にかけて、皆さんに約束します！","ENG":"On my honor as a knight, I promise you all!","TWN":"我以騎士的榮耀向大家保證！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"다들 들었지! 베이스 캠프의 최종 방어선은 우리가 맡는다!","JPN":"皆、聞いたな！　ベースキャンプの最終防衛線は我々が守る！","ENG":"You heard them! The base camp's last line of defense is ours to hold!","TWN":"大家都聽到了吧！營區的最後防線由我們來負責！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"목숨을 바치더라도, 카운터 분들을 보내는 거다!","JPN":"命に代えても、お二人の道を開くぞ！","ENG":"Even if it costs us our lives, we'll see the Counters through!","TWN":"就算要犧牲性命，也要讓制裁者們離開！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"자, 이제 니도 알겠지?","JPN":"さ、これで分かったやろ？","ENG":"Now do you get it?","TWN":"現在你明白了吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"지금 우리가 하려는 일의 무게를… 전장에서 카운터라는 게 어떤 의미인지를 말이다.","JPN":"今ウチらが背負ってるものの重さを……戦場でのカウンターがどんな存在かを。","ENG":"The weight of what we're about to do... what it means to be a Counter on the battlefield.","TWN":"作為制裁者的我們所背負的使命……在戰場上代表什麼。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"우리는 저 사람들의 희망인 기라.","JPN":"ウチらはあの人たちの希望なんや。","ENG":"We are their hope.","TWN":"我們是那些人的希望。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"네, 알겠어요. 앞으로는 망설이지 않을 게요.","JPN":"はい、分かりました。これからは迷いません。","ENG":"Yes. I understand. I won't hesitate again.","TWN":"嗯，我知道了。我不會再猶豫了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하핫! 가스나, 눈빛 봐줄만 하네. 알았으면 됐다.","JPN":"あははっ！　いい目つきになったな。分かってくれたら、それでええ。","ENG":"Haha! That look in your eyes. I like it! Glad you caught my drift.","TWN":"哈哈！你的眼神很堅定喔。知道就好。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};